import { NextResponse, type NextRequest } from "next/server";
import { postInputSchema, type ApiPost } from "@/lib/posts";

type RouteContext = {
  params: Promise<{
    id: string;
  }>;
};

const postsById = new Map<number, ApiPost>([
  [1, { id: 1, title: "First Post", content: "This is the first post" }],
  [2, { id: 2, title: "Second Post", content: "This is the second post" }],
]);

export async function GET(_request: NextRequest, { params }: RouteContext) {
  const { id } = await params;
  const postId = Number.parseInt(id, 10);

  if (Number.isNaN(postId)) {
    return NextResponse.json({ error: "Invalid post id" }, { status: 400 });
  }

  const post = postsById.get(postId) ?? {
    id: postId,
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: NextRequest, { params }: RouteContext) {
  const { id } = await params;
  const postId = Number.parseInt(id, 10);

  if (Number.isNaN(postId)) {
    return NextResponse.json({ error: "Invalid post id" }, { status: 400 });
  }

  const body = await request.json().catch(() => null);
  const parsed = postInputSchema.partial().safeParse(body);

  if (!parsed.success) {
    return NextResponse.json({ error: "Invalid request body" }, { status: 400 });
  }

  const updatedPost: ApiPost = {
    id: postId,
    title: parsed.data.title ?? `Post ${id}`,
    content: parsed.data.content ?? `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  postsById.set(postId, updatedPost);

  return NextResponse.json(updatedPost);
}

export async function DELETE(_request: NextRequest, { params }: RouteContext) {
  const { id } = await params;
  const postId = Number.parseInt(id, 10);

  if (Number.isNaN(postId)) {
    return NextResponse.json({ error: "Invalid post id" }, { status: 400 });
  }

  postsById.delete(postId);

  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}

