     9	
    10	const postsById = new Map<number, ApiPost>([
    11	  [1, { id: 1, title: "First Post", content: "This is the first post" }],
    12	  [2, { id: 2, title: "Second Post", content: "This is the second post" }],
    13	]);
    14	
    15	export async function GET(_request: NextRequest, { params }: RouteContext) {
    16	  const { id } = await params;
    17	  const postId = Number.parseInt(id, 10);
    18	
    19	  if (Number.isNaN(postId)) {
    20	    return NextResponse.json({ error: "Invalid post id" }, { status: 400 });
    21	  }
    22	
    23	  const post = postsById.get(postId) ?? {
    24	    id: postId,
    25	    title: `Post ${id}`,
    26	    content: `This is the content for post ${id}`,
    27	    createdAt: new Date().toISOString(),
    28	  };
    29	
    30	  return NextResponse.json(post);
    31	}
    32	
    33	export async function PUT(request: NextRequest, { params }: RouteContext) {
    34	  const { id } = await params;
    35	  const postId = Number.parseInt(id, 10);
    36	
    37	  if (Number.isNaN(postId)) {
    38	    return NextResponse.json({ error: "Invalid post id" }, { status: 400 });
    39	  }
    40	
    41	  const body = await request.json().catch(() => null);
    42	  const parsed = postInputSchema.partial().safeParse(body);
    43	
    44	  if (!parsed.success) {
    45	    return NextResponse.json({ error: "Invalid request body" }, { status: 400 });
    46	  }
    47	
    48	  const updatedPost: ApiPost = {
    49	    id: postId,
    50	    title: parsed.data.title ?? `Post ${id}`,
    51	    content: parsed.data.content ?? `Updated content for post ${id}`,
    52	    updatedAt: new Date().toISOString(),
    53	  };
    54	
    55	  postsById.set(postId, updatedPost);
    56	
    57	  return NextResponse.json(updatedPost);
    58	}
    59	
    60	export async function DELETE(_request: NextRequest, { params }: RouteContext) {
    61	  const { id } = await params;
    62	  const postId = Number.parseInt(id, 10);
    63	
    64	  if (Number.isNaN(postId)) {
    65	    return NextResponse.json({ error: "Invalid post id" }, { status: 400 });
    66	  }
    67	
    68	  postsById.delete(postId);
    69	
    70	  return NextResponse.json({ message: `Post ${id} deleted successfully` });
    71	}
