    35	async function fetchJson<T>(input: RequestInfo | URL, init?: RequestInit): Promise<T> {
    36	  const response = await fetch(input, init);
    37	
    38	  if (!response.ok) {
    39	    throw new Error(`Request failed with status ${response.status}`);
    40	  }
    41	
    42	  return response.json() as Promise<T>;
    43	}
