    45	export async function getRecentPosts(limit = 5): Promise<JsonPlaceholderPost[]> {
    46	  return fetchJson<JsonPlaceholderPost[]>(`${JSONPLACEHOLDER_BASE}/posts?_limit=${limit}`, {
    47	    cache: "no-store",
    48	  });
    49	}
    50	
    51	export async function getAllPosts(): Promise<JsonPlaceholderPost[]> {
    52	  return fetchJson<JsonPlaceholderPost[]>(`${JSONPLACEHOLDER_BASE}/posts`);
    53	}
